   var mrIds = serverRows.Select(o => o.MaterialRequisitionId).ToList();
   var appLookup = db.Approvals.Where(a => a.Type=="MaterialRequisition" && mrIds.Contains(a.TransEntry)).Select(a => new { a.TransEntry, a.EmployeeId }).ToList().ToLookup(a => a.TransEntry);
   var appUpdRows = db.ApprovalUpdates.Where(a => a.Type=="MaterialRequisition" && mrIds.Contains(a.TransEntry)).Select(a => new { a.TransEntry, a.ApprovalStatus, a.ApprovedBy, a.CreatedDate }).ToList();
   var appStatusLookup = appUpdRows.ToLookup(a => a.TransEntry);
   var chkAppStatusLookup = appUpdRows.GroupBy(a => a.TransEntry).ToDictionary(g => g.Key, g => g.GroupBy(l => l.ApprovedBy).Select(grp => grp.OrderByDescending(c => c.CreatedDate).First()).Select(a => a.ApprovalStatus).ToList());

